398	int main() {
399	    std::ios_base::sync_with_stdio(false);
400	    std::cin.tie(NULL);
401	    GLOBAL_START_TIME = std::chrono::steady_clock::now();
402	
403	    int N_CONST, M_CONST;
404	    std::cin >> N_CONST >> M_CONST; 
405	    std::vector<std::vector<int>> initial_stacks_main(M_CONST, std::vector<int>(N_CONST / M_CONST));
406	    for (int i = 0; i < M_CONST; ++i) {
407	        for (int j = 0; j < N_CONST / M_CONST; ++j) {
408	            std::cin >> initial_stacks_main[i][j];
409	        }
410	    }
411	    
412	    double beam_search_duration_budget = TIME_LIMIT_SECONDS_TOTAL * BEAM_SEARCH_TIME_LIMIT_SECONDS_PARAM;
413	    std::vector<int> current_plan_D = generate_initial_plan_beam_search(
414	        initial_stacks_main, 
415	        N_CONST, 
416	        M_CONST, 
417	        BEAM_WIDTH, 
418	        beam_search_duration_budget
419	    );
420	    
421	    if (current_plan_D.size() < (size_t)N_CONST && N_CONST > 0) {
422	        current_plan_D.resize(N_CONST, 0); 
423	    }
424	     if (N_CONST == 0) { 
425	        current_plan_D.clear(); 
426	    }
427	
428	    SimulationResult current_sim_res_eval = run_simulation(initial_stacks_main, current_plan_D, N_CONST, M_CONST, false); 
429	    long long current_energy = current_sim_res_eval.energy_cost;
430	    
431	    std::vector<int> best_plan_D = current_plan_D;
432	    long long best_energy = current_energy;
433	
434	    const int MAX_BLOCK_CHANGE_LEN = (N_CONST == 0) ? 0 : std::max(1, N_CONST / 15);
435	    double time_for_sa_start_offset = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
436	    
437	    while (true) {
438	        double elapsed_seconds_total = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
439	        if (elapsed_seconds_total >= TIME_LIMIT_SECONDS_TOTAL - 0.02) break; 
440	
441	        double elapsed_seconds_sa_phase = elapsed_seconds_total - time_for_sa_start_offset;
442	        double total_time_for_sa_phase = (TIME_LIMIT_SECONDS_TOTAL - 0.02) - time_for_sa_start_offset; 
443	        if (total_time_for_sa_phase <= 0.001) break; 
444	
445	        double progress_ratio = std::min(1.0, std::max(0.0, elapsed_seconds_sa_phase / total_time_for_sa_phase));
446	        double current_temp = T_INITIAL_SA * std::pow(T_FINAL_SA / T_INITIAL_SA, progress_ratio);
447	        current_temp = std::max(current_temp, T_FINAL_SA);
448	
449	        std::vector<int> new_plan_D = current_plan_D;
450	        long long new_energy;
451	        
452	        int k_change_start_idx = N_CONST; 
453	
454	        State state_at_change_point; 
455	        bool can_use_partial_simulation = false; 
456	
457	        double op_choice_rand = RGen.a_double(0.0, 1.0);
458	
459	        if (op_choice_rand < 0.35 && N_CONST > 0) { 
